     1→import { getLogger } from "@logtape/logtape";
     2→import type {
     3→	ProjectContributor as ProjectContributorBase,
     4→	ProjectDetailData,
     5→	ProjectError as ProjectErrorBase,
     6→	ProjectFeatureUsage,
     7→	ProjectInvestment,
     8→	ProjectTrendDataPoint as ProjectTrendDataPointBase,
     9→} from "@rudel/api-routes";
    10→import {
    11→	buildDateFilter,
    12→	escapeString,
    13→	queryClickhouse,
    14→} from "../clickhouse.js";
    15→
    16→const logger = getLogger(["rudel", "api", "project-service"]);
    17→
    18→const PROJECT_KEY_EXPR = `if(git_remote != '', git_remote, if(package_name != '', package_name, project_path))`;
    19→const PROJECT_DISPLAY_EXPR = `if(git_remote != '', arrayElement(splitByChar('/', git_remote), -1), arrayElement(splitByChar('/', project_path), -1))`;
    20→
    21→function buildProjectDisplaySubquery(
    22→	org: string,
    23→	escapedProjectPath: string,
    24→): string {
    25→	return `(
    26→    SELECT
    27→      if(
    28→        count() > 0,
    29→        any(${PROJECT_DISPLAY_EXPR}),
    30→        if(position('${escapedProjectPath}', '/') > 0, arrayElement(splitByChar('/', '${escapedProjectPath}'), -1), '${escapedProjectPath}')
    31→      ) as project_display
    32→    FROM rudel.session_analytics
    33→    WHERE organization_id = '${org}'
    34→      AND (
    35→        project_path = '${escapedProjectPath}'
    36→        OR git_remote = '${escapedProjectPath}'
    37→        OR ${PROJECT_KEY_EXPR} = '${escapedProjectPath}'
    38→      )
    39→      AND (git_remote != '' OR package_name != '' OR project_path != '')
    40→  )`;
    41→}
    42→
    43→export interface KnowledgeSilo {
    44→	project_path: string;
    45→	project_name?: string;
    46→	repository_name?: string;
    47→	sole_user: string;
    48→	sessions: number;
    49→	risk_level: "high" | "medium" | "low";
    50→}
    51→
    52→export interface ProjectActivity {
    53→	date: string;
    54→	project_path: string;
    55→	sessions: number;
    56→	unique_users: number;
    57→}
    58→
    59→export interface ProjectSummary {
    60→	total_projects: number;
    61→	projects_with_silos: number;
    62→	avg_users_per_project: number;
    63→	most_active_project: string;
    64→	most_active_sessions: number;
    65→}
    66→
    67→export type ProjectDetails = ProjectDetailData;
    68→
    69→export interface ProjectContributor extends ProjectContributorBase {
    70→	username?: string;
    71→	first_session: string;
    72→	last_session: string;
    73→}
    74→
    75→export interface ProjectError extends ProjectErrorBase {
    76→	first_seen: string;
    77→}
    78→
    79→export interface ProjectTrendDataPoint extends ProjectTrendDataPointBase {
    80→	project_name?: string;
    81→}
    82→
    83→/**
    84→ * Extract project name from path (last segment)
    85→ */
    86→function extractProjectName(projectPath: string): string {
    87→	if (!projectPath) return "";
    88→	const segments = projectPath.replace(/\\/g, "/").split("/").filter(Boolean);
    89→	return segments[segments.length - 1] || projectPath;
    90→}
    91→
    92→/**
    93→ * Extract repository name from path
    94→ */
    95→function extractRepositoryName(projectPath: string): string {
    96→	return extractProjectName(projectPath);
    97→}
    98→
    99→/**
   100→ * Get AI investment by project - where is time being spent?
   101→ */
   102→export async function getProjectInvestment(
   103→	orgId: string,
   104→	params: {
   105→		days?: number;
   106→		limit?: number;
   107→		offset?: number;
   108→		project_path?: string;
   109→		project_paths?: string[];
   110→	} = {},
   111→): Promise<ProjectInvestment[]> {
   112→	const {
   113→		days = 30,
   114→		limit = 20,
   115→		offset = 0,
   116→		project_path,
   117→		project_paths,
   118→	} = params;
   119→	const org = escapeString(orgId);
   120→	const d = Number(days);
   121→	const lim = Number(limit);
   122→	const off = Number(offset);
   123→
   124→	let projectFilter = "";
   125→	if (project_path) {
   126→		projectFilter = `AND project_path = '${escapeString(project_path)}'`;
   127→	} else if (project_paths && project_paths.length > 0) {
   128→		const escaped = project_paths.map((p) => `'${escapeString(p)}'`).join(", ");
   129→		projectFilter = `AND project_path IN (${escaped})`;
   130→	}
   131→
   132→	const query = `
   133→    WITH current_period AS (
   134→      SELECT
   135→        ${PROJECT_DISPLAY_EXPR} as project_display,
   136→        any(git_remote) as _git_remote,
   137→        any(project_path) as _project_path,
   138→        COUNT(*) as sessions,
   139→        COUNT(DISTINCT user_id) as unique_users,
   140→        SUM(ifNull(input_tokens, 0)) as input_tokens_sum,
   141→        SUM(ifNull(output_tokens, 0)) as output_tokens_sum,
   142→        SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
   143→        round(SUM(actual_duration_min), 2) as total_duration_min,
   144→        round(AVG(actual_duration_min), 2) as avg_session_duration_min,
   145→        round(AVG(success_score), 2) as success_rate
   146→      FROM rudel.session_analytics
   147→      WHERE ${buildDateFilter(d)}
   148→        AND organization_id = '${org}'
   149→        AND (git_remote != '' OR package_name != '' OR project_path != '')
   150→        ${projectFilter}
   151→      GROUP BY ${PROJECT_DISPLAY_EXPR}
   152→    ),
   153→    previous_period AS (
   154→      SELECT
   155→        ${PROJECT_DISPLAY_EXPR} as project_display,
   156→        round(AVG(success_score), 2) as prev_success_rate
   157→      FROM rudel.session_analytics
   158→      WHERE session_date >= now64(3) - INTERVAL ${d * 2} DAY
   159→        AND session_date < now64(3) - INTERVAL ${d} DAY
   160→        AND organization_id = '${org}'
   161→        AND (git_remote != '' OR package_name != '' OR project_path != '')
   162→        ${projectFilter}
   163→      GROUP BY ${PROJECT_DISPLAY_EXPR}
   164→    )
   165→    SELECT
   166→      c.project_display as repository,
   167→      c._git_remote as git_remote,
   168→      c._project_path as project_path,
   169→      c.sessions,
   170→      c.unique_users,
   171→      c.total_tokens,
   172→      c.input_tokens_sum as input_tokens,
   173→      c.output_tokens_sum as output_tokens,
   174→      c.total_duration_min,
   175→      c.avg_session_duration_min,
   176→      c.success_rate,
   177→      round((c.output_tokens_sum / 1000000.0) * 15.0 + (c.input_tokens_sum / 1000000.0) * 3.0, 4) as cost,
   178→      round(c.success_rate - ifNull(p.prev_success_rate, c.success_rate), 2) as success_rate_trend
   179→    FROM current_period c
   180→    LEFT JOIN previous_period p ON c.project_display = p.project_display
   181→    ORDER BY c.total_duration_min DESC
   182→    LIMIT ${lim}
   183→    OFFSET ${off}
   184→  `;
   185→
   186→	const results = await queryClickhouse<
   187→		ProjectInvestment & { git_remote?: string }
   188→	>(query);
   189→
   190→	return results.map((project) => ({
   191→		...project,
   192→		repository: project.repository || null,
   193→		git_remote: project.git_remote || undefined,
   194→	}));
   195→}
