   197→/**
   198→ * Get knowledge silos - projects with only one developer
   199→ */
   200→export async function getKnowledgeSilos(
   201→	orgId: string,
   202→	params: { days?: number; min_sessions?: number } = {},
   203→): Promise<KnowledgeSilo[]> {
   204→	const { days = 30, min_sessions = 5 } = params;
   205→	const org = escapeString(orgId);
   206→	const d = Number(days);
   207→	const minSess = Number(min_sessions);
   208→
   209→	const query = `
   210→    SELECT
   211→      project_path,
   212→      any(user_id) as sole_user,
   213→      COUNT(*) as sessions,
   214→      CASE
   215→        WHEN COUNT(*) >= 20 THEN 'high'
   216→        WHEN COUNT(*) >= 10 THEN 'medium'
   217→        ELSE 'low'
   218→      END as risk_level
   219→    FROM rudel.session_analytics
   220→    WHERE ${buildDateFilter(d)}
   221→      AND organization_id = '${org}'
   222→      AND project_path != ''
   223→    GROUP BY project_path
   224→    HAVING COUNT(DISTINCT user_id) = 1
   225→      AND COUNT(*) >= ${minSess}
   226→    ORDER BY sessions DESC
   227→  `;
   228→
   229→	const results = await queryClickhouse<KnowledgeSilo>(query);
   230→
   231→	return results.map((silo) => ({
   232→		...silo,
   233→		project_name: extractProjectName(silo.project_path),
   234→		repository_name: extractRepositoryName(silo.project_path),
   235→	}));
   236→}
