   283→/**
   284→ * Get project summary statistics
   285→ */
   286→export async function getProjectSummary(
   287→	orgId: string,
   288→	days = 30,
   289→): Promise<ProjectSummary> {
   290→	const org = escapeString(orgId);
   291→	const d = Number(days);
   292→
   293→	const query = `
   294→    WITH project_stats AS (
   295→      SELECT
   296→        project_path,
   297→        COUNT(*) as sessions,
   298→        COUNT(DISTINCT user_id) as users
   299→      FROM rudel.session_analytics
   300→      WHERE ${buildDateFilter(d)}
   301→        AND organization_id = '${org}'
   302→        AND project_path != ''
   303→      GROUP BY project_path
   304→    )
   305→    SELECT
   306→      COUNT(*) as total_projects,
   307→      countIf(users = 1 AND sessions >= 5) as projects_with_silos,
   308→      round(AVG(users), 2) as avg_users_per_project,
   309→      argMax(project_path, sessions) as most_active_project,
   310→      max(sessions) as most_active_sessions
   311→    FROM project_stats
   312→  `;
   313→
   314→	const result = await queryClickhouse<ProjectSummary>(query);
   315→	return (
   316→		result[0] || {
   317→			total_projects: 0,
   318→			projects_with_silos: 0,
   319→			avg_users_per_project: 0,
   320→			most_active_project: "",
   321→			most_active_sessions: 0,
   322→		}
   323→	);
   324→}
