   326→/**
   327→ * Get detailed metrics for a specific project
   328→ */
   329→export async function getProjectDetails(
   330→	orgId: string,
   331→	projectPath: string,
   332→	days = 30,
   333→): Promise<ProjectDetails | null> {
   334→	const org = escapeString(orgId);
   335→	const pp = escapeString(projectPath);
   336→	const d = Number(days);
   337→	const projectDisplaySubquery = buildProjectDisplaySubquery(org, pp);
   338→
   339→	const query = `
   340→    SELECT
   341→      any(project_path) as raw_project_path,
   342→      COUNT(*) as total_sessions,
   343→      SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
   344→      SUM(ifNull(input_tokens, 0)) as input_tokens_sum,
   345→      SUM(ifNull(output_tokens, 0)) as output_tokens_sum,
   346→      COUNT(DISTINCT user_id) as contributors_count,
   347→      countIf(success_score < 40) as errors_count,
   348→      ifNull(round(avgOrNull(actual_duration_min), 2), 0) as avg_session_duration_min,
   349→      ifNull(round(avgOrNull(success_score), 2), 0) as success_rate,
   350→      round(SUM(actual_duration_min), 2) as total_duration_min
   351→    FROM rudel.session_analytics
   352→    WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
   353→      AND ${buildDateFilter(d)}
   354→      AND organization_id = '${org}'
   355→      AND (git_remote != '' OR package_name != '' OR project_path != '')
   356→  `;
   357→
   358→	let results: (Omit<ProjectDetails, "project_path"> & {
   359→		raw_project_path: string;
   360→		input_tokens_sum: number;
   361→		output_tokens_sum: number;
   362→	})[];
   363→	try {
   364→		results = await queryClickhouse<
   365→			Omit<ProjectDetails, "project_path"> & {
   366→				raw_project_path: string;
   367→				input_tokens_sum: number;
   368→				output_tokens_sum: number;
   369→			}
   370→		>(query);
   371→	} catch (err) {
   372→		logger.error(
   373→			"getProjectDetails ClickHouse query failed for org={org} path={path}: {error}",
   374→			{ org: orgId, path: projectPath, error: String(err) },
   375→		);
   376→		throw err;
   377→	}
   378→
   379→	const [row] = results;
   380→	if (!row || row.total_sessions === 0) return null;
   381→	const cost =
   382→		row.output_tokens_sum * 0.000015 + row.input_tokens_sum * 0.000003;
   383→	return {
   384→		project_path: row.raw_project_path,
   385→		total_sessions: row.total_sessions,
   386→		total_tokens: row.total_tokens,
   387→		contributors_count: row.contributors_count,
   388→		errors_count: row.errors_count,
   389→		avg_session_duration_min: row.avg_session_duration_min,
   390→		success_rate: row.success_rate,
   391→		total_duration_min: row.total_duration_min,
   392→		cost: parseFloat(cost.toFixed(4)),
   393→	};
   394→}
