   396→/**
   397→ * Get contributors to a specific project
   398→ */
   399→export async function getProjectContributors(
   400→	orgId: string,
   401→	projectPath: string,
   402→	days = 30,
   403→): Promise<ProjectContributor[]> {
   404→	const org = escapeString(orgId);
   405→	const pp = escapeString(projectPath);
   406→	const d = Number(days);
   407→	const projectDisplaySubquery = buildProjectDisplaySubquery(org, pp);
   408→
   409→	const query = `
   410→    WITH project_totals AS (
   411→      SELECT COUNT(*) as total_sessions
   412→      FROM rudel.session_analytics
   413→      WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
   414→        AND ${buildDateFilter(d)}
   415→        AND organization_id = '${org}'
   416→        AND (git_remote != '' OR package_name != '' OR project_path != '')
   417→    )
   418→    SELECT
   419→      user_id,
   420→      COUNT(*) as sessions,
   421→      round(SUM(actual_duration_min), 2) as total_duration_min,
   422→      SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
   423→      toString(min(session_date)) as first_session,
   424→      toString(max(session_date)) as last_session,
   425→      round(COUNT(*) * 100.0 / (SELECT total_sessions FROM project_totals), 2) as contribution_percentage
   426→    FROM rudel.session_analytics
   427→    WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
   428→      AND ${buildDateFilter(d)}
   429→      AND organization_id = '${org}'
   430→      AND (git_remote != '' OR package_name != '' OR project_path != '')
   431→    GROUP BY user_id
   432→    ORDER BY sessions DESC
   433→  `;
   434→
   435→	return queryClickhouse<ProjectContributor>(query);
   436→}
