   438→/**
   439→ * Get feature usage for a specific project
   440→ */
   441→export async function getProjectFeatureUsage(
   442→	orgId: string,
   443→	projectPath: string,
   444→	days = 30,
   445→): Promise<ProjectFeatureUsage> {
   446→	const org = escapeString(orgId);
   447→	const pp = escapeString(projectPath);
   448→	const d = Number(days);
   449→	const projectDisplaySubquery = buildProjectDisplaySubquery(org, pp);
   450→
   451→	const adoptionQuery = `
   452→    SELECT
   453→      COUNT(*) as total_sessions,
   454→      countIf(length(subagent_types) > 0) as subagents_sessions,
   455→      countIf(length(skills) > 0) as skills_sessions,
   456→      countIf(length(slash_commands) > 0) as slash_commands_sessions
   457→    FROM rudel.session_analytics
   458→    WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
   459→      AND ${buildDateFilter(d)}
   460→      AND organization_id = '${org}'
   461→      AND (git_remote != '' OR package_name != '' OR project_path != '')
   462→  `;
   463→
   464→	const topSubagentsQuery = `
   465→    SELECT val as name, count() as count
   466→    FROM rudel.session_analytics
   467→    ARRAY JOIN subagent_types as val
   468→    WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
   469→      AND ${buildDateFilter(d)}
   470→      AND organization_id = '${org}'
   471→      AND (git_remote != '' OR package_name != '' OR project_path != '')
   472→      AND val != ''
   473→    GROUP BY val
   474→    ORDER BY count DESC
   475→    LIMIT 10
   476→  `;
   477→
   478→	const topSkillsQuery = `
   479→    SELECT val as name, count() as count
   480→    FROM rudel.session_analytics
   481→    ARRAY JOIN skills as val
   482→    WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
   483→      AND ${buildDateFilter(d)}
   484→      AND organization_id = '${org}'
   485→      AND (git_remote != '' OR package_name != '' OR project_path != '')
   486→      AND val != ''
   487→    GROUP BY val
   488→    ORDER BY count DESC
   489→    LIMIT 10
   490→  `;
   491→
   492→	const topSlashCommandsQuery = `
   493→    SELECT val as name, count() as count
   494→    FROM rudel.session_analytics
   495→    ARRAY JOIN slash_commands as val
   496→    WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
   497→      AND ${buildDateFilter(d)}
   498→      AND organization_id = '${org}'
   499→      AND (git_remote != '' OR package_name != '' OR project_path != '')
   500→      AND val != ''
   501→    GROUP BY val
   502→    ORDER BY count DESC
   503→    LIMIT 10
   504→  `;
   505→
   506→	const [adoptionResults, topSubagents, topSkills, topSlashCommands] =
   507→		await Promise.all([
   508→			queryClickhouse<{
   509→				total_sessions: number;
   510→				subagents_sessions: number;
   511→				skills_sessions: number;
   512→				slash_commands_sessions: number;
   513→			}>(adoptionQuery),
   514→			queryClickhouse<{ name: string; count: number }>(topSubagentsQuery),
   515→			queryClickhouse<{ name: string; count: number }>(topSkillsQuery),
   516→			queryClickhouse<{ name: string; count: number }>(topSlashCommandsQuery),
   517→		]);
   518→
   519→	if (adoptionResults.length === 0) {
   520→		return {
   521→			subagents_adoption_rate: 0,
   522→			skills_adoption_rate: 0,
   523→			slash_commands_adoption_rate: 0,
   524→			top_subagents: [],
   525→			top_skills: [],
   526→			top_slash_commands: [],
   527→		};
   528→	}
   529→
   530→	const [stats] = adoptionResults;
   531→	if (!stats)
   532→		return {
   533→			subagents_adoption_rate: 0,
   534→			skills_adoption_rate: 0,
   535→			slash_commands_adoption_rate: 0,
   536→			top_subagents: [],
   537→			top_skills: [],
   538→			top_slash_commands: [],
   539→		};
   540→	return {
   541→		subagents_adoption_rate:
   542→			stats.total_sessions > 0
   543→				? (stats.subagents_sessions / stats.total_sessions) * 100
   544→				: 0,
   545→		skills_adoption_rate:
   546→			stats.total_sessions > 0
   547→				? (stats.skills_sessions / stats.total_sessions) * 100
   548→				: 0,
   549→		slash_commands_adoption_rate:
   550→			stats.total_sessions > 0
   551→				? (stats.slash_commands_sessions / stats.total_sessions) * 100
   552→				: 0,
   553→		top_subagents: topSubagents,
   554→		top_skills: topSkills,
   555→		top_slash_commands: topSlashCommands,
   556→	};
   557→}
