   559→/**
   560→ * Get error patterns specific to a project
   561→ */
   562→export async function getProjectErrors(
   563→	orgId: string,
   564→	projectPath: string,
   565→	days = 30,
   566→): Promise<ProjectError[]> {
   567→	const org = escapeString(orgId);
   568→	const pp = escapeString(projectPath);
   569→	const d = Number(days);
   570→	const projectDisplaySubquery = buildProjectDisplaySubquery(org, pp);
   571→
   572→	const query = `
   573→    WITH error_extracts AS (
   574→      SELECT
   575→        session_id,
   576→        user_id,
   577→        session_date,
   578→        CASE
   579→          WHEN content LIKE '%OperationFailed%' THEN 'OperationFailed'
   580→          WHEN content LIKE '%UnknownError%' THEN 'UnknownError'
   581→          WHEN content LIKE '%ORPCError%' THEN 'ORPCError'
   582→          WHEN content LIKE '%TimeoutError%' THEN 'TimeoutError'
   583→          WHEN content LIKE '%TypeError%' THEN 'TypeError'
   584→          WHEN content LIKE '%ReferenceError%' THEN 'ReferenceError'
   585→          WHEN content LIKE '%Error:%' OR content LIKE '%error:%' THEN 'GenericError'
   586→          ELSE NULL
   587→        END as error_pattern
   588→      FROM rudel.session_analytics
